class TestScanCodePlaceholders(unittest.TestCase):
    """Test Go source placeholder scanning."""

    def _make_repo(self, files: dict[str, str]) -> pathlib.Path:
        """Create a temp repo structure. files maps relative paths to content."""
        tmpdir = tempfile.mkdtemp()
        root = pathlib.Path(tmpdir)
        for rel_path, content in files.items():
            full = root / rel_path
            full.parent.mkdir(parents=True, exist_ok=True)
            full.write_text(content, encoding="utf-8")
        return root

    def test_detects_not_implemented_string(self):
        root = self._make_repo({
            "api/cmd/flotsam/main.go": textwrap.dedent("""\
                package main

                func voiceCmd() {
                    fmt.Fprintln(os.Stderr, "flotsam voice: not yet implemented")
                }
            """),
        })
        results = check_placeholders.scan_code_placeholders(root)
        self.assertEqual(len(results), 1)
        self.assertEqual(results[0].category, "not_implemented")
        self.assertEqual(results[0].feature_hint, "voice")
        self.assertIn("not yet implemented", results[0].text)

    def test_detects_status_not_implemented(self):
        root = self._make_repo({
            "api/internal/handler/upload.go": textwrap.dedent("""\
                package handler

                func Upload(w http.ResponseWriter, r *http.Request) {
                    w.WriteHeader(http.StatusNotImplemented)
                }
            """),
        })
        results = check_placeholders.scan_code_placeholders(root)
        self.assertEqual(len(results), 1)
        self.assertEqual(results[0].category, "http_501")

    def test_detects_coming_soon(self):
        root = self._make_repo({
            "api/cmd/flotsam/main.go": textwrap.dedent("""\
                package main

                func searchCmd() {
                    fmt.Println("Search: coming soon")
                }
            """),
        })
        results = check_placeholders.scan_code_placeholders(root)
        cats = [r.category for r in results]
        self.assertIn("coming_soon", cats)

    def test_detects_todo_in_handler_dir(self):
        root = self._make_repo({
            "api/graph/resolver/schema.resolvers.go": textwrap.dedent("""\
                package resolver

                func (r *queryResolver) Items() {
                    // TODO: implement pagination
                    return nil, nil
                }
            """),
        })
        results = check_placeholders.scan_code_placeholders(root)
        cats = [r.category for r in results]
        self.assertIn("todo_in_handler", cats)

    def test_ignores_todo_in_non_handler(self):
        root = self._make_repo({
            "api/internal/item/service.go": textwrap.dedent("""\
                package item

                // TODO: optimize this later
                func Search() {}
            """),
        })
        results = check_placeholders.scan_code_placeholders(root)
        cats = [r.category for r in results]
        self.assertNotIn("todo_in_handler", cats)

    def test_excludes_generated_code(self):
        root = self._make_repo({
            "api/graph/generated/generated.go": textwrap.dedent("""\
                package generated

                // not yet implemented
                panic("not implemented")
            """),
        })
        results = check_placeholders.scan_code_placeholders(root)
        self.assertEqual(results, [])

    def test_excludes_test_files(self):
        root = self._make_repo({
            "api/internal/item/service_test.go": textwrap.dedent("""\
                package item

                // not yet implemented
                func TestSomething() {}
            """),
        })
        results = check_placeholders.scan_code_placeholders(root)
        self.assertEqual(results, [])

    def test_no_api_dir(self):
        root = self._make_repo({"README.md": "hello"})
        results = check_placeholders.scan_code_placeholders(root)
        self.assertEqual(results, [])


class TestScanDocClaims(unittest.TestCase):
    """Test documentation claim scanning."""

    def _make_repo(self, files: dict[str, str]) -> pathlib.Path:
        tmpdir = tempfile.mkdtemp()
        root = pathlib.Path(tmpdir)
        for rel_path, content in files.items():
            full = root / rel_path
            full.parent.mkdir(parents=True, exist_ok=True)
            full.write_text(content, encoding="utf-8")
        return root

    def test_detects_claim_word(self):
        root = self._make_repo({
            "README.md": "The MCP server is implemented and working.",
        })
        results = check_placeholders.scan_doc_claims(root)
        claim_words = [c.claim_word for c in results]
        self.assertIn("implemented", claim_words)

    def test_excludes_qualified_claims(self):
        root = self._make_repo({
            "README.md": "Voice capture is not yet implemented.",
        })
        results = check_placeholders.scan_doc_claims(root)
        self.assertEqual(results, [])

    def test_extracts_feature_hints(self):
        root = self._make_repo({
            "README.md": "MCP server is implemented with search support.",
        })
        results = check_placeholders.scan_doc_claims(root)
        self.assertTrue(len(results) > 0)
        all_hints = []
        for c in results:
            all_hints.extend(c.feature_hints)
        self.assertIn("mcp", all_hints)
        self.assertIn("search", all_hints)

    def test_skips_plans_directory(self):
