class TestMainExitCode(unittest.TestCase):
    """Test CLI exit codes and output."""

    def _run_main(self, placeholders, claims, mismatches, args=None):
        """Run main() with mocked scan functions and return exit code + stdout."""
        if args is None:
            args = []
        buf = io.StringIO()
        with (
            patch.object(check_placeholders, "scan_code_placeholders", return_value=placeholders),
            patch.object(check_placeholders, "scan_doc_claims", return_value=claims),
            patch.object(check_placeholders, "find_mismatches", return_value=mismatches),
            patch("sys.argv", ["check-placeholders.py"] + args),
            patch("sys.stdout", buf),
        ):
            code = check_placeholders.main()
        return code, buf.getvalue()

    def test_no_mismatches_exits_0(self):
        code, _ = self._run_main([], [], [])
        self.assertEqual(code, 0)

    def test_mismatches_exits_1(self):
        ph = check_placeholders.Placeholder("f.go", 1, "not_implemented", "x", "voice")
        claim = check_placeholders.DocClaim("README.md", 1, "y", "implemented", ["voice"])
        mm = check_placeholders.Mismatch(ph, claim, "voice")
        code, _ = self._run_main([ph], [claim], [mm])
        self.assertEqual(code, 1)

    def test_strict_mode_exits_1_on_any_placeholder(self):
        ph = check_placeholders.Placeholder("f.go", 1, "not_implemented", "x", "")
        code, _ = self._run_main([ph], [], [], args=["--strict"])
        self.assertEqual(code, 1)

    def test_strict_mode_exits_0_with_no_placeholders(self):
        code, _ = self._run_main([], [], [], args=["--strict"])
        self.assertEqual(code, 0)

    def test_json_output_format(self):
        ph = check_placeholders.Placeholder("f.go", 1, "not_implemented", "x", "voice")
        code, output = self._run_main([ph], [], [], args=["--json"])
        data = json.loads(output)
        self.assertEqual(data["placeholder_count"], 1)
        self.assertEqual(data["mismatch_count"], 0)
        self.assertFalse(data["has_mismatches"])
        self.assertEqual(code, 0)

    def test_json_with_mismatch(self):
        ph = check_placeholders.Placeholder("f.go", 1, "not_implemented", "x", "voice")
        claim = check_placeholders.DocClaim("README.md", 1, "y", "implemented", ["voice"])
        mm = check_placeholders.Mismatch(ph, claim, "voice")
        code, output = self._run_main([ph], [claim], [mm], args=["--json"])
        data = json.loads(output)
        self.assertTrue(data["has_mismatches"])
        self.assertEqual(data["mismatch_count"], 1)
        self.assertEqual(code, 1)


